// // This module counts down from 15 on each positive edge of the clock and resets to 16 when the reset signal is asserted.
module up_counter (
    input clk,
    input reset,
    output reg [3:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 4'b0000;
        else
            count <= count + 1;
    end
endmodule
